import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';

export default function OrderSuccess() {
  const navigate = useNavigate();
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    // Trigger entrance animation
    const t = setTimeout(() => setVisible(true), 50);
    return () => clearTimeout(t);
  }, []);

  return (
    <div className="max-w-md mx-auto min-h-screen bg-gray-50 flex flex-col">

      {/* Navy top section */}
      <div
        className="px-5 pt-14 pb-20 text-center flex-shrink-0"
        style={{ background: 'linear-gradient(160deg, #006491 0%, #004d6e 100%)' }}
      >
        <div
          className="text-8xl mb-4 transition-all duration-500"
          style={{ transform: visible ? 'scale(1)' : 'scale(0)', opacity: visible ? 1 : 0 }}
        >
          🎉
        </div>
        <h1 className="text-white font-black text-3xl mb-2">ההזמנה נשלחה!</h1>
        <p className="text-blue-200 text-sm">המטבח שלנו כבר עובד על הפיצה שלך</p>
      </div>

      {/* Action Cards */}
      <div className="px-4 -mt-8 space-y-3 pb-10">

        {/* Track Order Card */}
        <button
          onClick={() => navigate('/tracker')}
          className="w-full bg-tomato rounded-2xl p-5 shadow-lg text-right flex items-center gap-4 active:scale-95 transition"
        >
          <div className="flex-1">
            <p className="text-white font-black text-lg">עקוב אחרי ההזמנה</p>
            <p className="text-white/70 text-sm mt-0.5">צפה בסטטוס בזמן אמת</p>
          </div>
          <div className="text-4xl">📍</div>
        </button>

        {/* Info Card */}
        <div className="bg-white rounded-2xl shadow-sm p-5 space-y-3">
          <div className="flex items-center gap-3">
            <span className="text-2xl">⏱️</span>
            <div>
              <p className="font-bold text-gray-800">זמן אספקה משוער</p>
              <p className="text-gray-400 text-sm">20–40 דקות</p>
            </div>
          </div>
          <div className="flex items-center gap-3 pt-3 border-t border-gray-50">
            <span className="text-2xl">📱</span>
            <div>
              <p className="font-bold text-gray-800">עדכונים אוטומטיים</p>
              <p className="text-gray-400 text-sm">תקבל עדכון כשהפיצה בדרך</p>
            </div>
          </div>
        </div>

        {/* Back to Menu */}
        <button
          onClick={() => navigate('/')}
          className="w-full py-4 rounded-2xl border-2 border-gray-200 text-gray-700 font-bold bg-white hover:bg-gray-50 transition active:scale-95"
        >
          🍕 חזרה לתפריט
        </button>
      </div>
    </div>
  );
}
